1	const BASE_PREMIUMS: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	};
7	
8	const PROCESSING_FEE = 5;
9	
10	function ceilToWholeGold(amount: number): number {
11	  return Math.ceil(Math.round(amount * 1e6) / 1e6);
12	}
13	
14	export function quote(input: { items: Array<{ type: string }> }): number {
15	  const itemsTotal = input.items.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
16	  const total = itemsTotal * 1.1 + PROCESSING_FEE;
17	  return ceilToWholeGold(total);
18	}
19	
20	export function claim(_input: unknown): number {
21	  return undefined as unknown as number;
22	}
